import{_ as e,o as t,c as s,Q as i}from"./chunks/framework.b67c47e6.js";const f=JSON.parse('{"title":"Issues Management","description":"","frontmatter":{},"headers":[],"relativePath":"guide/issues/index.md","filePath":"guide/issues/index.md","lastUpdated":1773939149000}'),a={name:"guide/issues/index.md"},r=i('<h1 id="issues-management" tabindex="-1">Issues Management <a class="header-anchor" href="#issues-management" aria-label="Permalink to &quot;Issues Management&quot;">​</a></h1><p>The Issues view provides a centralized overview of all production issues and quality control records across a project.</p><nav class="table-of-contents"><ul><li><a href="#overview">Overview</a></li><li><a href="#issue-categories">Issue Categories</a></li><li><a href="#issue-fields">Issue Fields</a></li><li><a href="#creating-issues">Creating Issues</a></li><li><a href="#resolving-issues">Resolving Issues</a></li><li><a href="#filtering">Filtering</a></li></ul></nav><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>At the top, a summary card shows:</p><ul><li>Total issue count</li><li>Breakdown by category: <strong>Quality Control</strong> issues and <strong>Production Issues</strong></li></ul><p>Below the summary, a data table lists all issues with their details.</p><h2 id="issue-categories" tabindex="-1">Issue Categories <a class="header-anchor" href="#issue-categories" aria-label="Permalink to &quot;Issue Categories&quot;">​</a></h2><table><thead><tr><th>Category</th><th>Description</th></tr></thead><tbody><tr><td><strong>Quality Control</strong></td><td>Issues related to product quality, compliance, or inspection findings.</td></tr><tr><td><strong>Production Issue</strong></td><td>Problems encountered during the manufacturing process (delays, equipment, material defects).</td></tr></tbody></table><h2 id="issue-fields" tabindex="-1">Issue Fields <a class="header-anchor" href="#issue-fields" aria-label="Permalink to &quot;Issue Fields&quot;">​</a></h2><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Title</strong></td><td>Short description of the issue.</td></tr><tr><td><strong>Description</strong></td><td>Detailed explanation of the problem.</td></tr><tr><td><strong>Category</strong></td><td>Quality control or production issue.</td></tr><tr><td><strong>Constructible</strong></td><td>The assembly or module affected.</td></tr><tr><td><strong>Created by</strong></td><td>The user who reported the issue.</td></tr><tr><td><strong>Created at</strong></td><td>When the issue was reported.</td></tr><tr><td><strong>Status</strong></td><td>Open or solved.</td></tr><tr><td><strong>Pictures</strong></td><td>Optional photos or screenshots attached to the issue.</td></tr></tbody></table><h2 id="creating-issues" tabindex="-1">Creating Issues <a class="header-anchor" href="#creating-issues" aria-label="Permalink to &quot;Creating Issues&quot;">​</a></h2><p>Issues can be created from two places:</p><ol><li><strong>Issues view</strong> — Click the create button to add a new issue to any constructible.</li><li><strong>3D Viewer</strong> — While viewing a constructible, click the issues button to report a problem directly from the production floor. You can attach the current part information for context.</li></ol><h2 id="resolving-issues" tabindex="-1">Resolving Issues <a class="header-anchor" href="#resolving-issues" aria-label="Permalink to &quot;Resolving Issues&quot;">​</a></h2><p>To close an issue:</p><ol><li>Open the issue detail.</li><li>Mark it as <strong>solved</strong>.</li><li>Add a resolution comment explaining how it was fixed.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Issues on design templates can be solved with a new design revision, which applies the fix to all future instances of that design.</p></div><h2 id="filtering" tabindex="-1">Filtering <a class="header-anchor" href="#filtering" aria-label="Permalink to &quot;Filtering&quot;">​</a></h2><p>Use the table controls to filter issues by:</p><ul><li>Category (quality control / production issue)</li><li>Status (open / solved)</li><li>User</li><li>Date range</li></ul>',21),o=[r];function n(l,d,u,c,h,g){return t(),s("div",null,o)}const m=e(a,[["render",n]]);export{f as __pageData,m as default};
